import { PublicActionPage } from '@domain/publicActionPage';
import { useEffect, useMemo } from 'react';
import { useController, useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { Address } from '../../ActionPageView/ActionPageLayout/ActionPageBody/ActionPageForm/Fields/Address/Address';
import { FormAddressControlProps } from '../AddressControl/FormAddressControl';
import { FormCityStateInput } from '../AddressInputs/FormCityStateInput';
import { FormInputControl } from '../FormInputControl';
import { EmploymentControl } from '.';

type FormKeys = {
  employed: string;
  employerAddress: string;
  employerName: string;
  employerZip: string;
  occupation: string;
};

export type FormEmploymentControlProps = Pick<
  FormAddressControlProps,
  'fieldPrefix' | 'fieldPrefixDelimiter' | 'showLine2'
> & {
  actionPage?: PublicActionPage;
  employerAddressType?: 'complete' | 'zip' | 'city_state';
  formKeys?: FormKeys;
  includeEmployerAddress?: boolean;
  includeEmployerName?: boolean;
  includeOccupation?: boolean;
  occupationHelpText?: string;
  occupationLabel?: string;
  occupationOptions?: string[] | null;
  regions?: string[];
  requireEmployerAddress?: boolean;
  requireEmployerName?: boolean;
  requireEmployment?: boolean;
  requireOccupation?: boolean;
  showRadio?: boolean;
};

export const FormEmploymentControl = ({
  actionPage,
  employerAddressType = 'complete',
  fieldPrefix,
  fieldPrefixDelimiter,
  formKeys = {
    employed: 'employed',
    employerAddress: '',
    employerName: 'employerName',
    employerZip: 'postalCode',
    occupation: 'occupation',
  },
  includeEmployerAddress = false,
  includeEmployerName = false,
  includeOccupation = false,
  occupationHelpText,
  occupationLabel,
  occupationOptions,
  regions = ['US'],
  requireEmployerAddress,
  requireEmployerName,
  requireEmployment = false,
  requireOccupation,
  showLine2,
  showRadio = true,
}: FormEmploymentControlProps) => {
  const { t } = useTranslation(['common', 'customFields', 'donors']);
  const { clearErrors, control, formState, setValue, watch } = useFormContext();

  const {
    field: { onChange: onCurrentlyEmployedChange, value: currentlyEmployed },
    fieldState: { error: currentlyEmployedError },
  } = useController({
    control,
    name: formKeys.employed,
  });

  const isCurrentlyEmployed = watch(formKeys.employed);
  const selectedOccupation = watch(formKeys.occupation);

  const allowedCountries = useMemo(
    () => (!regions?.length || regions?.includes('IN') ? undefined : regions),
    [regions]
  ) as FormAddressControlProps['allowedCountries'];

  useEffect(() => {
    if (!isCurrentlyEmployed) {
      setValue('employerName', selectedOccupation);
    }
  }, [isCurrentlyEmployed, selectedOccupation, setValue]);

  const filteredOccupationOptions = useMemo(
    () => (includeOccupation ? occupationOptions?.filter((o) => Boolean(o)) : undefined),
    [occupationOptions, includeOccupation]
  );

  // Set occupation defaults when changing between employed and not employed
  const nonEmployedOptions = useMemo<string[]>(
    () => t('donors:donorForms.contactInformation.occupationOptions', { returnObjects: true }),
    [t]
  );
  useEffect(() => {
    if (
      // This would be the case if switching from employed to not employed
      !isCurrentlyEmployed &&
      !nonEmployedOptions.includes(selectedOccupation)
    ) {
      setValue(formKeys.occupation, 'retired');
    } else if (
      // This would be the case if switching from not employed to employed
      isCurrentlyEmployed &&
      nonEmployedOptions.includes(selectedOccupation)
    ) {
      setValue(formKeys.occupation, filteredOccupationOptions?.[0] || '');
      setValue(formKeys.employerName, '');
    }
  }, [
    setValue,
    formKeys.occupation,
    formKeys.employerName,
    isCurrentlyEmployed,
    selectedOccupation,
    nonEmployedOptions,
    filteredOccupationOptions,
  ]);

  useEffect(() => {
    if (requireEmployment && !includeOccupation && !includeEmployerName) {
      setValue(formKeys.occupation, 'retired');
      setValue(formKeys.employerName, 'retired');
    }
  }, [
    formKeys.occupation,
    formKeys.employerName,
    includeEmployerName,
    includeOccupation,
    requireEmployment,
    requireEmployerName,
    requireOccupation,
    setValue,
  ]);

  useEffect(() => {
    if (isCurrentlyEmployed === '' && includeOccupation) {
      setValue(formKeys.occupation, 'retired');
    }
    // run once on mount
  }, []);

  useEffect(() => {
    // Clear error from radio field after value is selected
    if (typeof isCurrentlyEmployed === 'boolean' && formState?.errors?.employed) {
      clearErrors('employed');
    }
  }, [clearErrors, formState?.errors?.employed, isCurrentlyEmployed]);

  return (
    <div className="flex w-full flex-col gap-4">
      <EmploymentControl
        currentlyEmployed={currentlyEmployed}
        errors={{
          currentlyEmployed: currentlyEmployedError?.message,
        }}
        formKeys={{
          employerName: formKeys.employerName,
          occupation: formKeys.occupation,
        }}
        includeEmployerName={includeEmployerName}
        includeOccupation={includeOccupation}
        isRequired={requireEmployment}
        occupationHelpText={occupationHelpText}
        occupationLabel={occupationLabel}
        occupationOptions={filteredOccupationOptions}
        onCurrentlyEmployedChange={onCurrentlyEmployedChange}
        requireEmployerName={requireEmployerName}
        requireOccupation={requireOccupation}
        showRadio={showRadio}
      />
      {isCurrentlyEmployed &&
        includeEmployerAddress &&
        (employerAddressType === 'zip' ? (
          <FormInputControl
            formControlProps={{ className: 'my-0' }}
            isRequired={requireEmployerAddress}
            label={t('customFields:employment.employerZip')}
            name={formKeys.employerZip}
          />
        ) : employerAddressType === 'city_state' ? (
          <FormCityStateInput
            allowedCountries={allowedCountries}
            cityLabel={t('customFields:employment.employerCity')}
            countryLabel={t('customFields:employment.employerCountry')}
            fieldPrefix={fieldPrefix}
            fieldPrefixDelimiter={fieldPrefixDelimiter}
            isRequired={requireEmployerAddress}
            stateLabel={t('customFields:employment.employerState')}
          />
        ) : (
          <Address
            actionPage={actionPage}

